class Account(ComplexModel):
    account_number = String
    balance = Float

class FinancialService(ServiceBase):
    accounts = {
        "12345": Account(account_number="12345", balance=1000.0),
        "67890": Account(account_number="67890", balance=2000.0),
    }

    @rpc(String, _returns=Float, soap_action='getBalance')
    def getBalance(self, account_number):
        if account_number not in self.accounts:
            raise SoapFault('AccountNotFound', f'Account {account_number} not found.')
        return self.accounts[account_number].balance

    @rpc(String, Float, _returns=String, soap_action='transferFunds')
    def transferFunds(self, from_account, amount):
        if from_account not in self.accounts:
            raise SoapFault('AccountNotFound', f'Account {from_account} not found.')
        if self.accounts[from_account].balance < amount:
            raise SoapFault('InsufficientFunds', 'Insufficient funds for transfer.')
        self.accounts[from_account].balance -= amount
        return f'Transferred {amount} from {from_account}.'

    @rpc(String, _returns=Account, soap_action='getAccountInfo')
    def getAccountInfo(self, account_number):
        if account_number not in self.accounts:
            raise SoapFault('AccountNotFound', f'Account {account_number} not found.')
        return self.accounts[account_number]

